import gsap from "gsap";
import $ from "jquery";

/* ---------- SCROLL ---------- */

export const scrollTopHide = (selector) => {
	const elem = document.querySelector(selector);
	elem?.classList.remove("show");
};

export const scrollTopShow = (selector) => {
	const elem = document.querySelector(selector);
	elem?.classList.add("show");
};

export function showFixedHeader() {
	$(".head.fixed").css({ transition: "all 0.7s" }).addClass("show").removeClass("hide");
}

export function hideFixedHeader() {
	$(".head.fixed").css({ transition: "all 0.4s" }).removeClass("show").addClass("hide");
}

/* ---------- POPUP ---------- */

export const openPopup = (selector) => {
	const popup = $(selector);
	const popupContent = popup.find(".popup__content");

	$("body").addClass("hidden");
	popup.addClass("is-open");

	const tl = gsap.timeline();

	tl.to(selector, {
		opacity: 1,
		visibility: "visible",
		duration: 0.1,
		ease: "power1.out",
	})
		.to(popupContent, {
			translateX: 0,
			duration: 0.1,
			ease: "power1.out",
		})
		.then(() => {
			scroll?.stop();

			const popupForm = popup.find("form");
			if (popupForm.length) {
				const firstInput = popupForm.find("input").not("[type=hidden]")[0];
				$(firstInput).focus();
			}
		});
};

export const closePopup = () => {
	$("body").removeClass("hidden");
	$(".popup").removeClass("is-open");
	scroll?.start();

	gsap.timeline()
		.to(".popup__content", {
			translateX: "100%",
			duration: 0.1,
			ease: "power1.out",
		})
		.to(".popup", {
			opacity: 0,
			duration: 0.1,
			ease: "power1.out",
		})
		.to(".popup", {
			visibility: "hidden",
			duration: 0,
			ease: "power1.out",
		});
};

/* ---------- MOBILE MENU ---------- */

export const openMMenu = (burgerBtns) => {
	const tl = gsap.timeline();
	const mm = document.querySelector(".mm");
	const mmBg = mm.querySelector(".mm__bg"),
		mmLayout = mm.querySelector(".mm__layout");
	document.body.classList.add("hidden");
	mm.classList.add("show");
	tl.to(mmBg, { opacity: 1, duration: 0.5 });
	tl.to(mmLayout, { translateX: "0%", duration: 0.5 }, "-=0.3");
};

export const closeMMenu = () => {
	const mm = document.querySelector(".mm");
	if (!mm) return;
	const tl = gsap.timeline();
	const mmBg = mm.querySelector(".mm__bg"),
		mmLayout = mm.querySelector(".mm__layout");
	document.body.classList.remove("hidden");
	tl.to(mmLayout, { translateX: "-100%", duration: 0.5 });
	tl.to(mmBg, { opacity: 0, duration: 0.5 }, "-=0.3").then(() => {
		mm.classList.remove("show");
	});
};

/* ---------- DROPDOWN ---------- */

export const toggleDropdown = () => {
	const dropdowns = document.querySelectorAll(".dropdown");
	if (!dropdowns) return;

	Array.from(dropdowns).forEach((dropdown) => {
		const title = dropdown.querySelector(".dropdown__value"),
			list = dropdown.querySelector(".dropdown__list");
		const items = list.querySelectorAll(".dropdown__item");

		title.addEventListener("click", (e) => {
			if (window.getComputedStyle(list).position === "absolute") {
				if (dropdown.classList.contains("active")) {
					dropdown.classList.remove("active");
				} else {
					dropdown.classList.add("active");
				}
			}
		});
		Array.from(items).forEach((item) => {
			item.addEventListener("click", (e) => {
				if (window.getComputedStyle(list).position === "absolute") {
					if (dropdown.classList.contains("multiple")) {
						const checkboxes = dropdown.querySelectorAll("input[type=checkbox]:checked");
						const values = Array.from(checkboxes).map((item) => {
							const label = item.closest("label");
							const text = label.querySelector("span.text").textContent;
							return text;
						});
						const textEl = title.querySelector("span.text");
						const restEl = title.querySelector("span.rest");
						const defaultTitle = title.dataset.defaultTitle || "";
						const fullText = values.length ? values.join(", ") : defaultTitle;
						textEl.textContent = fullText;
						let rest = 0;
						if (restEl) {
							restEl.textContent = "";
							if (values.length && textEl.scrollWidth > textEl.clientWidth) {
								let fitCount = 0;
								let testText = "";
								for (let i = 0; i < values.length; i++) {
									const candidate = i === 0 ? values[i] : testText + ", " + values[i];
									textEl.textContent = candidate;
									if (textEl.scrollWidth > textEl.clientWidth) break;
									testText = candidate;
									fitCount = i + 1;
								}
								rest = values.length - fitCount;

								if (rest > 0) {
									textEl.textContent = testText;
									restEl.textContent = "+" + rest;
								}
							}
						}
						if (rest > 0) {
							restEl.style.display = "inline-block";
						} else {
							restEl.style.display = "none";
						}
					} else {
						const text = e.currentTarget.querySelector("span.text").textContent;
						title.querySelector("span.text").textContent = text;
						dropdown.classList.remove("active");
					}
				}
			});
		});
	});
	document.addEventListener("click", (e) => {
		if (!e.target.closest(".dropdown")) {
			Array.from(dropdowns).forEach((drop) => drop.classList.remove("active"));
		}
	});
};

/* ---------- FILTER ---------- */

export const showFilter = () => {
	const catalogFilter = document.querySelector(".catalog__filter");

	if (!catalogFilter) return;

	const catalogFilterBtn = document.querySelector(".catalog__filter_toggle");

	catalogFilterBtn.addEventListener("click", (e) => {
		document.body.classList.add("hidden");
		catalogFilter.classList.add("active");
	});
};

export const hideFilter = () => {
	const catalogFilter = document.querySelector(".catalog__filter");

	if (!catalogFilter) return;

	const catalogFilterBtn = document.querySelector(".catalog__filter_close");

	catalogFilterBtn.addEventListener("click", (e) => {
		document.body.classList.remove("hidden");
		catalogFilter.classList.remove("active");
	});
};

/* ---------- ACCORDION ---------- */

export const toggleAccordion = () => {
	const accordions = document.querySelectorAll(".accordion");

	if (!accordions.length) return;

	Array.from(accordions).forEach((acc) => {
		const title = acc.querySelector(".accordion_title"),
			content = acc.querySelector(".accordion_content"),
			accBody = acc.querySelector(".accordion_body");

		title.addEventListener("click", (e) => {
			const height = accBody.offsetHeight;
			if (acc.classList.contains("active")) {
				acc.classList.remove("active");
				gsap.to(content, { height: 0 });
			} else {
				acc.classList.add("active");
				gsap.to(content, { height: `${height}px` });
			}
		});
	});
};

/* ---------- CLIPBOARD ---------- */

export const clipboardCopy = () => {
	const copyLinks = document.querySelectorAll(".copy-link");

	if (!copyLinks) return;

	copyLinks.forEach((link) => {
		link.addEventListener("click", (e) => {
			e.preventDefault();
			const link = e.currentTarget;
			const copiedText = link.dataset.copied;
			link.disabled = true;

			window.navigator.clipboard.writeText(copiedText).then(() => {
				const tooltip = document.createElement("div");
				tooltip.classList.add("tooltip");
				tooltip.textContent = "Скопировано!";

				document.body.appendChild(tooltip);
				tooltip.style.left = e.clientX + "px";
				tooltip.style.top = e.clientY - 5 + "px";
				tooltip.classList.add("active");

				setTimeout(() => {
					tooltip.classList.remove("active");
					tooltip.textContent = "";
					document.body.removeChild(tooltip);
					link.disabled = false;
				}, 3000);
			});
		});
	});
};

/* ---------- SHARE ---------- */

export const sharePage = () => {
	const shareBtns = document.querySelectorAll(".share-btn");

	if (!shareBtns.length) return;

	shareBtns.forEach((btn) => {
		btn.addEventListener("click", (e) => {
			const url = location.href;
			const title = document.querySelector("title").textContent;

			if (navigator.share) {
				navigator.share({ title, url }).catch(() => {
					copyToClipboardFallback(url);
				});
			} else {
				copyToClipboardFallback(url);
			}
		});
	});
};

function copyToClipboardFallback(text) {
	if (navigator.clipboard) {
		navigator.clipboard.writeText(text).then(() => {
			alert("Ссылка скопирована в буфер обмена");
		});
	} else {
		const textarea = document.createElement("textarea");
		textarea.value = text;
		textarea.style.position = "fixed";
		textarea.style.opacity = "0";
		document.body.appendChild(textarea);
		textarea.select();
		document.execCommand("copy");
		document.body.removeChild(textarea);
		alert("Ссылка скопирована в буфер обмена");
	}
}

/* ---------- TABS ---------- */

export const toggleTabs = () => {
	const tabs = document.querySelectorAll(".tab");

	if (!tabs) return;
	tabs.forEach((btn) => {
		btn.addEventListener("click", () => {
			const id = btn.dataset.tab;

			document.querySelectorAll(".tab").forEach((t) => t.classList.remove("active"));
			document.querySelectorAll(".tab-content").forEach((c) => c.classList.remove("active"));

			btn.classList.add("active");
			document.querySelector(`[data-content="${id}"]`).classList.add("active");
		});
	});
};

/* ---------- COUNTER ---------- */

export const setCounterValue = () => {
	const counters = document.querySelectorAll(".counter");

	if (!counters.length) return;

	counters.forEach((counter) => {
		counter.addEventListener("click", (e) => {
			if (e.target.closest(".inc") || e.target.closest(".dec")) {
				e.preventDefault();

				const counterValue = counter.querySelector(".counter_value");
				if (e.target.closest(".inc")) counterValue.value++;
				if (e.target.closest(".dec"))
					counterValue.value = counterValue.value > 0 ? counterValue.value - 1 : 0;
			}
		});
	});
};
