import Swiper from "swiper";
import {
  Autoplay,
  EffectFade,
  Pagination,
  Grid,
  Navigation,
  Scrollbar,
  Thumbs,
} from "swiper/modules";

export const initHeroSlider = () => {
  const heroSlider = document.querySelector(".hero__images_slider");
  const heroContent = document.querySelector(".hero__content");
  const heroContentSlider = document.querySelector(".hero__content_slider");
  if (!heroSlider) return;

  const contentSlider = new Swiper(heroContentSlider, {
    loop: true,
    allowTouchMove: false,
    fadeEffect: {
      crossFade: true,
    },
    speed: 1500,
    autoplay: {
      delay: 7000,
      disableOnInteraction: false,
    },
    autoHeight: false,
    effect: "fade",
    spaceBetween: 10,
    modules: [Autoplay, Navigation, EffectFade],
    navigation: {
      prevEl: heroContent.querySelector(".swiper_prev"),
      nextEl: heroContent.querySelector(".swiper_next"),
    },
  });

  const slider = new Swiper(heroSlider, {
    loop: true,
    allowTouchMove: false,
    fadeEffect: {
      crossFade: true,
    },
    speed: 1500,
    autoplay: {
      delay: 7000,
      disableOnInteraction: false,
    },
    autoHeight: false,
    effect: "fade",
    spaceBetween: 10,
    modules: [Autoplay, Navigation, EffectFade],
    navigation: {
      prevEl: heroContent.querySelector(".swiper_prev"),
      nextEl: heroContent.querySelector(".swiper_next"),
    },
  });
};

