export const inithistoryOrderSliders = () => {
  const newCatalog = document.querySelectorAll(".history__order_list.swiper");

  if (!newCatalog.length) return;

  newCatalog.forEach((item) => {
    const slider = new Swiper(item, {
      slidesPerView: 1.2,
      observer: true,
      observeParents: true,
      slidesPerGroup: 1,
      spaceBetween: 8,
      autoHeight: true,
      breakpoints: {
        320: {
          slidesPerView: 1.2,
          spaceBetween: 8,
        },
        375: {
          slidesPerView: 1.5,
          spaceBetween: 8,
        },
        450: {
          slidesPerView: 1.8,
          spaceBetween: 8,
        },
        576: {
          slidesPerView: 2.1,
          spaceBetween: 8,
        },
        768: {
          slidesPerView: 2.5,
          spaceBetween: 12,
        },
        991: {
          slidesPerView: 3.5,
          spaceBetween: 16,
        },
        1200: {
          slidesPerView: 4.1,
          spaceBetween: 16,
        },
        1400: {
          slidesPerView: 4.8,
          spaceBetween: 20,
        },
      },
    });
    item.swiperInstance = slider;
  });
};

