export const catalogElementSlider = () => {
  const picture = document.querySelector(".catalog-element__picture_slider");
  const thumbs = document.querySelector(".catalog-element__picture_thumbs");

  if (!picture || !thumbs) return;

  const thumbsSlider = new Swiper(thumbs, {
    slidesPerView: "auto",
    spaceBetween: 12,
    watchSlidesProgress: true,
  });

  const pictureSlider = new Swiper(picture, {
    slidesPerView: 1,
    modules: [Thumbs, EffectFade, Autoplay],
    thumbs: {
      swiper: thumbsSlider,
    },
    speed: 1000,
    autoplay: {
      delay: 5000,
    },
    effect: "fade",
    fadeEffect: {
      crossFade: true,
    },
  });
};

export const contactsSliders = () => {
  const contactsSliders = document.querySelectorAll(
    ".contact-card__slider.swiper",
  );

  if (!contactsSliders.length) return;

  contactsSliders.forEach((item) => {
    const slider = new Swiper(item, {
      slidesPerView: "auto",
      spaceBetween: 12,
      modules: [Scrollbar],
      scrollbar: {
        el: item.querySelector(".swiper-scrollbar"),
        hide: false,
      },
      freeMode: true,
    });
  });
};
