export const contactsMap = () => {
	const mapContainer = document.querySelector("#contacts-map");

	if (!mapContainer) return;

	const offices = [
		{
			city: "nn",
			title: "Производство и склад готовой продукции",
			coords: [56.263252, 43.614438],
		},

		{
			city: "msk",
			title: "Представительство в Москве",
			coords: [55.772021, 37.876593],
		},

		{
			city: "spb",
			title: "Представительство в Санкт-Петербурге",
			coords: [59.932928, 30.446869],
		},
	];

	ymaps.ready(() => {
		const map = new ymaps.Map("contacts-map", {
			center: [57.5, 45],
			zoom: 5,
			controls: ["smallMapDefaultSet"],
		});

		map.behaviors.disable("scrollZoom");

		const objectManager = new ymaps.ObjectManager({
			clusterize: true,
			gridSize: 64,
		});

		map.geoObjects.add(objectManager);

		const tabs = document.querySelectorAll(".contacts__tab");
		const cards = document.querySelectorAll(".contact-card");

		const render = (city = "all") => {
			objectManager.removeAll();

			let filteredOffices = offices;

			if (city !== "all") {
				filteredOffices = offices.filter((office) => office.city === city);
			}

			const features = filteredOffices.map((office, index) => ({
				type: "Feature",
				id: index,
				geometry: {
					type: "Point",
					coordinates: office.coords,
				},
				properties: {
					balloonContent: office.title,
					hintContent: office.title,
				},
			}));

			objectManager.add({
				type: "FeatureCollection",
				features,
			});

			cards.forEach((card) => {
				if (city === "all" || card.dataset.city === city) {
					card.style.display = "";
				} else {
					card.style.display = "none";
				}
			});

			if (filteredOffices.length === 1) {
				const office = filteredOffices[0];
				map.setCenter(office.coords, 13, { duration: 400 });
			} else {
				const bounds = objectManager.getBounds();
				if (bounds) {
					map.setBounds(bounds, {
						checkZoomRange: true,
						zoomMargin: 80,
						duration: 400,
					});
					setTimeout(() => {
						if (map.getZoom() > 10) {
							map.setZoom(10, { duration: 200 });
						}
					}, 300);
				}
			}
		};

		tabs.forEach((tab) => {
			tab.addEventListener("click", () => {
				tabs.forEach((item) => {
					item.classList.remove("current");
				});
				tab.classList.add("current");
				render(tab.dataset.city);
			});
		});

		render();
	});
};
