import gsap from "gsap";

export function initScrollAnimations() {
	const els = document.querySelectorAll(
		".anim-fade-in, .anim-fade-in-up, .anim-fade-in-left, .anim-fade-in-right, .anim-scale-in, .anim-stagger, .anim-counter"
	);
	if (!els.length) return;

	const observer = new IntersectionObserver(
		(entries) => {
			entries.forEach((entry) => {
				if (entry.isIntersecting) {
					entry.target.classList.add("anim-visible");
					observer.unobserve(entry.target);
				}
			});
		},
		{ threshold: 0.15 }
	);

	els.forEach((el) => observer.observe(el));
}

export function initCounters() {
	const counters = document.querySelectorAll("[data-counter-target]");
	if (!counters.length) return;

	counters.forEach((counter) => {
		const target = parseInt(counter.dataset.counterTarget, 10);
		if (isNaN(target)) return;

		const checkVisible = () => {
			if (counter.classList.contains("anim-visible") && !counter.dataset.counted) {
				counter.dataset.counted = "true";
				animateNumber(counter, target);
			}
		};

		const observer = new IntersectionObserver(
			(entries) => {
				entries.forEach((entry) => {
					if (entry.isIntersecting) {
						counter.classList.add("anim-visible");
						checkVisible();
						observer.unobserve(counter);
					}
				});
			},
			{ threshold: 0.5 }
		);

		observer.observe(counter);
	});
}

function animateNumber(el, target) {
	const isFloat = target % 1 !== 0;
	const duration = Math.min(Math.max(target * 0.02, 0.8), 3);

	gsap.fromTo(
		el,
		{ textContent: 0 },
		{
			textContent: target,
			duration,
			ease: "power2.out",
			snap: isFloat ? (value) => Math.round(value * 10) / 10 : (value) => Math.round(value),
			onUpdate: function () {
				const val = this.targets()[0].textContent;
				el.textContent = isFloat ? parseFloat(val).toFixed(1) : val;
			},
		}
	);
}
